'use client';

import { useEffect, useState } from 'react';
import Image from 'next/image';
import { Testimonial } from '@/lib/types';

export default function UserTestimonialsPage() {
  const [testimonials, setTestimonials] = useState<Testimonial[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingTestimonial, setEditingTestimonial] = useState<Testimonial | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    location: '',
    university: '',
    program: '',
    quote: '',
    rating: 5,
    image: '',
    country: '',
    isActive: true,
    featured: false
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  useEffect(() => {
    fetchTestimonials();
  }, []);

  const showMessage = (type: 'success' | 'error', text: string) => {
    setMessage({ type, text });
    setTimeout(() => setMessage(null), 5000);
  };

  const fetchTestimonials = async () => {
    try {
      setLoading(true);
      const response = await fetch('/api/admin/testimonials');
      if (response.ok) {
        const data = await response.json();
        setTestimonials(data);
      } else {
        setTestimonials([]);
        showMessage('error', 'Failed to fetch testimonials');
      }
    } catch (error) {
      setTestimonials([]);
      showMessage('error', 'Network error while fetching testimonials');
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    try {
      const url = editingTestimonial ? `/api/admin/testimonials/${editingTestimonial._id}` : '/api/admin/testimonials';
      const method = editingTestimonial ? 'PUT' : 'POST';

      const response = await fetch(url, {
        method,
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData),
      });

      if (response.ok) {
        showMessage('success', editingTestimonial ? 'Testimonial updated successfully!' : 'Testimonial created successfully!');
        fetchTestimonials();
        setShowForm(false);
        setEditingTestimonial(null);
        setFormData({
          name: '',
          location: '',
          university: '',
          program: '',
          quote: '',
          rating: 5,
          image: '',
          country: '',
          isActive: true,
          featured: false
        });
      } else {
        const errorData = await response.json();
        showMessage('error', `Failed to ${editingTestimonial ? 'update' : 'create'} testimonial: ${errorData.error || 'Unknown error'}`);
      }
    } catch (error) {
      showMessage('error', 'Network error. Please check your connection and try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleEdit = (testimonial: Testimonial) => {
    setEditingTestimonial(testimonial);
    setFormData({
      name: testimonial.name,
      location: testimonial.location,
      university: testimonial.university,
      program: testimonial.program,
      quote: testimonial.quote,
      rating: testimonial.rating,
      image: testimonial.image || '',
      country: testimonial.country,
      isActive: testimonial.isActive,
      featured: testimonial.featured
    });
    setShowForm(true);
  };

  const handleDelete = async (id: string) => {
    if (confirm('Are you sure you want to delete this testimonial?')) {
      try {
        const response = await fetch(`/api/admin/testimonials/${id}`, {
          method: 'DELETE',
        });

        if (response.ok) {
          showMessage('success', 'Testimonial deleted successfully!');
          fetchTestimonials();
        } else {
          showMessage('error', 'Failed to delete testimonial');
        }
      } catch (error) {
        showMessage('error', 'Network error while deleting testimonial');
      }
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="text-lg">Loading testimonials...</div>
      </div>
    );
  }

  return (
    <div className="px-2 sm:px-4 lg:px-6 xl:px-8">
